  ('heelevel3-d0d1b9a2-moex-00129', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ac2adf20', 'sub-heelevel3-d0d1b9a2-02', NULL, 'single_choice', '下列有關特種基金之敘述，何者正確？', '["信託基金不納入附屬單位預算，故非屬特種基金", "特種基金僅能以歲入、歲出之一部編入總預算", "特種基金均編製附屬單位預算", "特種基金均具有專款專用特性"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "cd1a3a6e0114", "answer_pdf_sha1": "d3d24e840bdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00130', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ac2adf20', 'sub-heelevel3-d0d1b9a2-02', NULL, 'single_choice', '依政府會計準則公報第9號規定，下列何者依其預算編列型態，須依規定設置預算控制科目：', '["行政院人事行政總處", "農業特別收入基金", "交通作業基金", "臺灣糖業股份有限公司"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "cd1a3a6e0114", "answer_pdf_sha1": "d3d24e840bdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00131', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ac2adf20', 'sub-heelevel3-d0d1b9a2-02', NULL, 'single_choice', '教育部於X1年度預算設備及投資科目編列增撥國立臺灣大學校務基金5億元，依中央政府普通 公務單位會計制度之一致規定及國立大學校院校務基金會計制度之一致規定，下列那兩項正確？', '["教育部借記採權益法之投資", "教育部借記補助特種基金", "國立臺灣大學校務基金貸記基 金", "國立臺灣大學校務基金貸記公庫撥款收入"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "cd1a3a6e0114", "answer_pdf_sha1": "d3d24e840bdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00132', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ac2adf20', 'sub-heelevel3-d0d1b9a2-02', NULL, 'single_choice', '依政府會計準則公報第4號規定，固定資產以交換方式取得且具有商業實質時，若甲機關換出資 產的公允價值無法可靠衡量，而該換出資產的帳面金額介於向乙機關換入資產的帳面金額及其公 允價值之間，其中該公允價值最高，而三者各相差10萬元，下列會計處理之敘述，何者正確？', '["甲機關認列財產交易利益", "乙機關要支付現金予甲機關", "乙機關認列財產交易利益", "甲乙兩機關均應認列財產交易利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "cd1a3a6e0114", "answer_pdf_sha1": "d3d24e840bdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00133', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ac2adf20', 'sub-heelevel3-d0d1b9a2-02', NULL, 'single_choice', '依中央總會計制度規定，總預算列有移用以前年度歲計賸餘預算數，於年度結束時，未移用部分， 應作下列何種分錄？', '["借：累計餘絀，貸：移用以前年度歲計賸餘預算數", "借：移用以前年度歲計賸餘預算數，貸：歲計餘絀", "借：收支調度數，貸：歲計餘絀", "不作分錄"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "cd1a3a6e0114", "answer_pdf_sha1": "d3d24e840bdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL),
  ('heelevel3-d0d1b9a2-moex-00134', 'heelevel3-d0d1b9a2', 'heelevel3-d0d1b9a2-moex-113-ac2adf20', 'sub-heelevel3-d0d1b9a2-02', NULL, 'single_choice', '中央政府甲機關於X1年1月1日以10億元設立A作業基金，投資比例100%。A作業基金X1 年度本期短絀2億元，X2年度本期賸餘4億元，除填補虧損2億元外，當年度賸餘解繳國庫1億 元。依中央總會計制度、中央政府整體資產負債表編製注意事項規定，X1年度及X2年度中央政 府整體資產負債表之「採權益法之投資」科目，應沖銷之數額分別為何？', '["8億元、11億元", "8億元、12億元", "10億元、11億元", "10億元、12億元"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:58+00:00", "source_pdf_sha1": "cd1a3a6e0114", "answer_pdf_sha1": "d3d24e840bdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "321", "s": "0908", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "政府會計", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "會計"}'::jsonb, NULL)
